import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import Modal from '../components/Modal';
import './Dashboard.css';

function Dashboard() {
    const { user, logout } = useAuth();
    const [companies, setCompanies] = useState([]);
    const [workers, setWorkers] = useState([]);
    const [reports, setReports] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('companies');

    // Modal states
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState(''); // 'company', 'worker'
    const [editingItem, setEditingItem] = useState(null);
    const [formData, setFormData] = useState({});

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [companiesRes, workersRes, reportsRes] = await Promise.all([
                api.get('/companies'),
                api.get('/workers'),
                api.get('/reports')
            ]);

            setCompanies(companiesRes.data);
            setWorkers(workersRes.data);
            setReports(reportsRes.data);
        } catch (error) {
            console.error('Error fetching data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = async () => {
        await logout();
        window.location.href = '/login';
    };

    if (loading) {
        return <div className="loading">Loading...</div>;
    }

    return (
        <div className="dashboard">
            <div className="dashboard-header">
                <div>
                    <h1>Super Admin Dashboard</h1>
                    <p>Welcome, {user?.name}</p>
                </div>
                <button onClick={handleLogout} className="logout-btn">Logout</button>
            </div>

            <div className="stats-grid">
                <div className="stat-card">
                    <h3>{companies.length}</h3>
                    <p>Total Companies</p>
                </div>
                <div className="stat-card">
                    <h3>{workers.length}</h3>
                    <p>Total Workers</p>
                </div>
                <div className="stat-card">
                    <h3>{reports.length}</h3>
                    <p>Total Reports</p>
                </div>
                <div className="stat-card">
                    <h3>{companies.filter(c => c.is_active).length}</h3>
                    <p>Active Companies</p>
                </div>
            </div>

            <div className="dashboard-tabs">
                <button 
                    className={activeTab === 'companies' ? 'active' : ''} 
                    onClick={() => setActiveTab('companies')}
                >
                    Companies
                </button>
                <button 
                    className={activeTab === 'workers' ? 'active' : ''} 
                    onClick={() => setActiveTab('workers')}
                >
                    Workers
                </button>
                <button 
                    className={activeTab === 'reports' ? 'active' : ''} 
                    onClick={() => setActiveTab('reports')}
                >
                    Reports
                </button>
            </div>

            <div className="dashboard-content">
                {activeTab === 'companies' && (
                    <div className="table-container">
                        <h2>Companies</h2>
                        <table>
                            <thead>
                                <tr>
                                    <th>Name</th>
                                    <th>Location</th>
                                    <th>Supervisor</th>
                                    <th>Workers</th>
                                    <th>Status</th>
                                </tr>
                            </thead>
                            <tbody>
                                {companies.map(company => (
                                    <tr key={company.id}>
                                        <td>{company.name}</td>
                                        <td>{company.location || 'N/A'}</td>
                                        <td>{company.supervisor?.name || 'Not Assigned'}</td>
                                        <td>{company.workers_count || 0}</td>
                                        <td>
                                            <span className={`status ${company.is_active ? 'active' : 'inactive'}`}>
                                                {company.is_active ? 'Active' : 'Inactive'}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}

                {activeTab === 'workers' && (
                    <div className="table-container">
                        <h2>All Workers</h2>
                        <table>
                            <thead>
                                <tr>
                                    <th>Name</th>
                                    <th>Company</th>
                                    <th>Team</th>
                                    <th>Position</th>
                                    <th>Contact</th>
                                    <th>Status</th>
                                </tr>
                            </thead>
                            <tbody>
                                {workers.map(worker => (
                                    <tr key={worker.id}>
                                        <td>{worker.name}</td>
                                        <td>{worker.company?.name}</td>
                                        <td><span className="team-badge">{worker.team}</span></td>
                                        <td>{worker.position || 'N/A'}</td>
                                        <td>{worker.contact_number || 'N/A'}</td>
                                        <td>
                                            <span className={`status ${worker.is_active ? 'active' : 'inactive'}`}>
                                                {worker.is_active ? 'Active' : 'Inactive'}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}

                {activeTab === 'reports' && (
                    <div className="table-container">
                        <h2>All Reports</h2>
                        <table>
                            <thead>
                                <tr>
                                    <th>Title</th>
                                    <th>Company</th>
                                    <th>Supervisor</th>
                                    <th>Date</th>
                                    <th>File</th>
                                </tr>
                            </thead>
                            <tbody>
                                {reports.map(report => (
                                    <tr key={report.id}>
                                        <td>{report.title}</td>
                                        <td>{report.company?.name}</td>
                                        <td>{report.supervisor?.name}</td>
                                        <td>{new Date(report.report_date).toLocaleDateString()}</td>
                                        <td>
                                            {report.file_path ? 
                                                <a href={`http://localhost:8000/storage/${report.file_path}`} target="_blank" rel="noopener noreferrer">
                                                    View
                                                </a> : 'No file'
                                            }
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
}

export default Dashboard;
